playwright.script:
export default async function run({ page, input, emit }) {
  const target = input?.prompt || input?.value || input?.result || "https://example.com";
  const url = typeof target === "string" && target.trim() ? target.trim() : "https://example.com";
  await page.goto(url, { waitUntil: "domcontentloaded" });
  const title = await page.title();
  emit("result", title);
  emit("value", { title, url: page.url() });
  return { title, url: page.url() };
}

